def solve(grid):
    import copy
    grid = [row[:] for row in grid]
    H, W = len(grid), len(grid[0])

    # Identify bars from bottom row
    bar_cells = set()
    bars_by_color = {}  # color -> list of (col, body_len, top_row)

    for c in range(W):
        if grid[H-1][c] != 0:
            endpoint = grid[H-1][c]
            # Walk up to find top endpoint
            for r in range(H-2, -1, -1):
                if grid[r][c] == endpoint:
                    body_len = H - 1 - r - 1
                    if body_len > 0:
                        bar_cells.add((H-1, c))
                        bar_cells.add((r, c))
                        for br in range(r+1, H-1):
                            bar_cells.add((br, c))
                        if endpoint not in bars_by_color:
                            bars_by_color[endpoint] = []
                        bars_by_color[endpoint].append((c, body_len, r))
                    break
                elif grid[r][c] == 0:
                    break

    # For each endpoint color, count legend cells and replace target bar
    for color in bars_by_color:
        legend_count = 0
        for r in range(H):
            for c in range(W):
                if grid[r][c] == color and (r, c) not in bar_cells:
                    legend_count += 1

        bars_sorted = sorted(bars_by_color[color], key=lambda x: -x[1])
        if 1 <= legend_count <= len(bars_sorted):
